const QUESTIONS_ECIH_C1 = [
  { id:80101, domain:1, level:1, question:"Which triad forms the foundation of information security principles?", options:["Confidentiality, Integrity, and Availability together defining the core security objectives","Prevention, Detection, and Response describing the phases of a defensive security strategy","Authentication, Authorization, and Accounting are the three fundamental security services","Identification, Encryption, and Auditing representing the pillars of data protection controls"], correct:0, explanation:"The CIA triad is confidentiality, integrity, and availability; AAA describes access services, not the core triad." },
  { id:80102, domain:1, level:1, question:"What does confidentiality ensure within the CIA triad of information security?", options:["Information remains accurate, complete, and unaltered by any unauthorized modification attempt","Information is accessible only to those authorized to view it and protected from disclosure","Systems and data remain accessible and usable whenever legitimate users need to reach them","Every action taken on a system is uniquely attributable to a specific authenticated user"], correct:1, explanation:"Confidentiality restricts disclosure; keeping data unaltered is integrity, and access uptime is availability." },
  { id:80103, domain:1, level:1, question:"What does integrity guarantee about information in a secure system environment?", options:["Data is kept secret and disclosed only to individuals who have proper authorization to it","Data and services are reachable by authorized users at all required and expected times","Data remains accurate and complete and is not modified by unauthorized parties at all","Data usage is logged so that each transaction can be traced back to its originator later"], correct:2, explanation:"Integrity is about accuracy and unauthorized modification; secrecy is confidentiality." },
  { id:80104, domain:1, level:1, question:"What does availability mean as an objective of the CIA triad?", options:["Only authorized individuals can read the protected information stored within the system","The stored data cannot be altered without detection by any unauthorized individual today","Communications between two parties are encrypted so that eavesdroppers cannot read them","Authorized users can access systems, data, and resources reliably when they need them"], correct:3, explanation:"Availability ensures reliable access; encryption supports confidentiality, not availability." },
  { id:80105, domain:1, level:2, question:"A denial-of-service attack most directly compromises which element of the CIA triad?", options:["Availability, because it prevents legitimate users from accessing the targeted service","Confidentiality, because attackers read sensitive data flowing across the target network","Integrity, because the attacker silently modifies records stored in the backend database","Non-repudiation, because the source of the transaction can no longer be proven at all"], correct:0, explanation:"DoS floods resources to deny access, harming availability; it does not read or alter data." },
  { id:80106, domain:1, level:2, question:"An attacker alters figures in a financial database without authorization. Which principle is violated?", options:["Availability, since users are now unable to reach the affected financial records at all in this context","Integrity, since the data has been modified by an unauthorized party without any permission","Confidentiality, since the attacker has disclosed the records to outside parties online","Authentication, since the attacker bypassed the login verification mechanism entirely"], correct:1, explanation:"Unauthorized modification of data breaks integrity, not availability or confidentiality." },
  { id:80107, domain:1, level:2, question:"Which term describes a weakness in a system that a threat could exploit?", options:["A threat is any circumstance with the potential to cause damage to an information asset","A risk is the probability that a given threat will exploit a particular system weakness","A vulnerability is a flaw or weakness that can be leveraged to cause harm to the assets","An exploit is the actual tool or code used to take advantage of a system flaw somewhere"], correct:2, explanation:"A vulnerability is the weakness itself; a threat is the potential cause, and risk is likelihood." },
  { id:80108, domain:1, level:2, question:"Which term best describes a potential cause of an unwanted incident that may harm assets?", options:["A vulnerability is the specific weakness in the asset that permits the harm to occur here","A control is the safeguard implemented to reduce the likelihood or impact of the harm","An exposure is a state in which an asset is susceptible to loss from an attacker somewhere","A threat is any potential event or actor capable of causing harm to information assets"], correct:3, explanation:"A threat is the potential cause; the weakness it targets is the vulnerability." },
  { id:80109, domain:1, level:3, question:"Risk in information security is most accurately expressed as a function of which factors?", options:["The likelihood that a threat exploits a vulnerability combined with the resulting impact","The total number of vulnerabilities present in a system multiplied by the asset value in this context","The count of active threats detected against the network over a defined time period","The cost of the security controls deployed relative to the annual security budget set"], correct:0, explanation:"Risk = likelihood (threat exploiting vulnerability) x impact; raw vulnerability counts alone are not risk." },
  { id:80110, domain:1, level:2, question:"What is an attack vector in the context of information security?", options:["The specific weakness in software or hardware that permits an attacker to succeed here","The path or means by which an attacker gains access to a target to deliver a payload","The overall business impact that results once an attack has been fully carried out","The set of logs and artifacts left behind after an attacker compromises a host machine"], correct:1, explanation:"An attack vector is the route/means of access; the weakness itself is the vulnerability." },
  { id:80111, domain:1, level:3, question:"Which scenario best illustrates the concept of an attack surface?", options:["A single unpatched service running on a server that an attacker chooses to exploit here","The estimated financial loss an organization faces from a successful intrusion event","The sum of all points where an unauthorized user could try to enter or extract the data","The documented sequence of steps an analyst follows during a forensic investigation"], correct:2, explanation:"The attack surface is the totality of exposed entry points, not one service or a loss estimate." },
  { id:80112, domain:1, level:1, question:"Which of the following is best classified as a malware incident?", options:["An employee accidentally emailing a spreadsheet to the wrong internal recipient by mistake","A power outage that causes the primary data center to fail over to backup systems","A misconfigured firewall rule that briefly blocks legitimate customer traffic for a while","A ransomware infection that encrypts files across many endpoints and demands payment"], correct:3, explanation:"Ransomware is malicious software, a malware incident; the others are errors or availability issues." },
  { id:80113, domain:1, level:1, question:"A flood of traffic from many compromised hosts overwhelms a web server. This is a:", options:["Distributed denial-of-service incident that exhausts resources to deny legitimate access","Data breach incident in which confidential customer records are exfiltrated to attackers","Insider threat incident where a trusted employee abuses granted system privileges here","Phishing incident that tricks users into revealing their account login credentials online"], correct:0, explanation:"Many compromised hosts flooding a target is DDoS; no data theft or insider abuse is described." },
  { id:80114, domain:1, level:2, question:"An employee with legitimate access copies confidential data to sell to a competitor. This is a:", options:["External data breach caused by an outside attacker penetrating the perimeter defenses","Insider threat incident, since a trusted user abuses authorized access maliciously here","Denial-of-service incident that disrupts the availability of the organization's systems","Social engineering incident in which the user was manipulated into an unwanted action"], correct:1, explanation:"A trusted user abusing access for gain is an insider threat, not an external breach." },
  { id:80115, domain:1, level:2, question:"Which incident type involves tricking users into divulging credentials via a fraudulent email?", options:["Cross-site scripting, which injects malicious script into a trusted web application page","SQL injection, which manipulates database queries through unsanitized input fields here","Phishing, a form of social engineering that lures victims into revealing sensitive data","Man-in-the-middle, which intercepts communications between two legitimate parties quietly"], correct:2, explanation:"Fraudulent emails luring credentials are phishing; XSS and SQLi are code-injection web attacks." },
  { id:80116, domain:1, level:2, question:"An attacker injects malicious SQL through a web form to read the backend database. This is a:", options:["Cross-site request forgery incident forcing a user to submit an unwanted request here","Buffer overflow incident overwriting memory to execute attacker-controlled code remotely","Session hijacking incident where the attacker steals a valid user session token quietly","SQL injection incident exploiting unsanitized input to manipulate the database queries"], correct:3, explanation:"Malicious SQL via input is SQL injection; CSRF and overflow attack different mechanisms." },
  { id:80117, domain:1, level:2, question:"Unauthorized access occurs when someone:", options:["Gains entry to systems or data without permission or beyond their granted rights","Deliberately floods a network to make a service unavailable to the real users online","Accidentally deletes a shared file that they were fully authorized to manage already","Encrypts their own laptop's disk using an approved corporate encryption tool at work"], correct:0, explanation:"Unauthorized access is entry without permission; flooding is DoS and encryption is not access." },
  { id:80118, domain:1, level:3, question:"Which example most clearly represents a web application attack rather than another category?", options:["A malicious USB drive left in a parking lot infects a workstation with a trojan later","A cross-site scripting payload stored in a comment field executes in visitors' browsers","A stolen backup tape containing customer records is found missing from the storage room","A contractor uses shared credentials to log in outside of normal business hours today"], correct:1, explanation:"Stored XSS executing in browsers is a web app attack; the others are physical, loss, or misuse." },
  { id:80119, domain:1, level:3, question:"An organization discovers customer records were exfiltrated and posted online. This is primarily a:", options:["Denial-of-service incident that made the customer portal temporarily unavailable to users","Reconnaissance incident in which the attacker only scanned for open ports on the host","Data breach incident involving the unauthorized disclosure of confidential information","Policy violation in which an employee installed unapproved personal software on a laptop"], correct:2, explanation:"Exfiltration and disclosure of confidential records is a data breach, not a DoS or scan." },
  { id:80120, domain:1, level:2, question:"Which of the following is an example of email-based social engineering?", options:["A brute-force attack repeatedly guessing passwords against a login portal all night long","A rootkit hiding malicious processes from the operating system's task list quietly today","An ARP spoofing attack redirecting local network traffic through the attacker's machine","A spear-phishing message impersonating the CFO requesting an urgent wire transfer now"], correct:3, explanation:"Impersonating an executive by email to induce action is social engineering; brute force is not." },
  { id:80121, domain:1, level:1, question:"A worm is best described as malware that:", options:["Self-replicates and spreads across networks without a host file or any user action","Requires a user to open an infected attachment before it can execute its payload at all","Encrypts files and demands a ransom payment to restore access to the affected data","Silently records keystrokes and transmits the captured credentials to a remote attacker"], correct:0, explanation:"A worm self-propagates without a host; needing a host file describes a virus, not a worm." },
  { id:80122, domain:1, level:1, question:"What is an Indicator of Compromise (IOC)?", options:["A predictive sign that an attack is about to occur but has not yet taken place at all","Forensic evidence such as file hashes or IPs suggesting a system may be compromised","A written policy describing how staff must respond once an incident has been declared","A control implemented to prevent attackers from reaching a protected asset in advance"], correct:1, explanation:"An IOC is evidence a compromise likely occurred; a sign an attack is coming is a precursor." },
  { id:80123, domain:1, level:2, question:"How does a precursor differ from an indicator in incident handling?", options:["A precursor is stronger evidence than an indicator and always confirms an incident occurred","A precursor appears only after containment while an indicator appears before detection","A precursor signals an incident may occur later; an indicator signals one may be occurring","A precursor is a physical artifact while an indicator is always a network log entry only"], correct:2, explanation:"Precursors suggest a future incident; indicators suggest one is occurring or has occurred." },
  { id:80124, domain:1, level:2, question:"Which of the following is an example of a precursor rather than an indicator?", options:["Antivirus alerting that a known trojan was found running on a corporate workstation today","Multiple failed then one successful login from an unfamiliar foreign IP address at night","A file integrity monitor reporting that a system binary was unexpectedly modified quietly","Web server logs showing a vulnerability scanner probing the site before any real attack"], correct:3, explanation:"A pre-attack scan is a precursor; detected malware or altered binaries are indicators of an incident." },
  { id:80125, domain:1, level:3, question:"An Indicator of Attack (IOA) focuses primarily on:", options:["The intent and behavior of an attacker in progress rather than static forensic artifacts","The residual file-based evidence left behind after an intrusion has already concluded fully","The hardware inventory an organization maintains for its asset management purposes only","The regulatory penalties an organization faces after a confirmed data breach event occurs"], correct:0, explanation:"IOAs emphasize attacker behavior/intent in real time; static leftover artifacts are IOCs." },
  { id:80126, domain:1, level:2, question:"Which is a common network-based indicator of a possible compromise?", options:["A scheduled backup job completing successfully during its normal maintenance window today","Unusual outbound traffic to an unknown external IP at abnormal hours of the night","A user resetting their own password through the approved self-service portal at work now","An application update being deployed by IT during a planned and approved change window"], correct:1, explanation:"Anomalous outbound traffic suggests compromise; routine backups and updates are normal activity." },
  { id:80127, domain:1, level:1, question:"Which of the following would most likely be treated as an IOC?", options:["A firewall successfully blocking an inbound connection exactly as its rules intend to","A user logging in during their normal shift from their assigned workstation at the office","A file hash matching a known piece of malware found on a corporate endpoint device","A patch being applied to a server during a scheduled and approved maintenance window"], correct:2, explanation:"A known-malware hash on a host is a classic IOC; blocked connections and normal logins are not." },
  { id:80128, domain:1, level:1, question:"According to NIST SP 800-61, what are the four phases of the incident response life cycle?", options:["Identification; Protection; Detection; Response as defined by the core framework functions","Plan; Do; Check; Act repeated continuously to improve the security posture over the time","Reconnaissance; Weaponization; Delivery; Exploitation across the full attack lifecycle model","Preparation; Detection and Analysis; Containment, Eradication and Recovery; Post-Incident"], correct:3, explanation:"NIST 800-61 uses those four phases; PDCA and the kill chain are different models." },
  { id:80129, domain:1, level:2, question:"In the NIST incident response life cycle, which phase includes establishing an IR team and tools?", options:["Preparation, which builds the capability, policies, and resources before incidents occur","Detection and Analysis, which identifies and validates that an incident has occurred here","Containment, Eradication and Recovery, which limits damage and restores affected systems","Post-Incident Activity, which captures the lessons learned after the incident finally closes"], correct:0, explanation:"Preparation builds capability in advance; detection validates incidents once they happen." },
  { id:80130, domain:1, level:2, question:"Which phase of the IR life cycle aims to limit the damage of an ongoing incident?", options:["Preparation, which readies the team and the tools before any incident takes place at all","Containment, which isolates affected systems to prevent the incident from spreading further","Detection and Analysis, which confirms and characterizes the suspected incident carefully","Post-Incident Activity, which documents lessons learned to improve any future response work"], correct:1, explanation:"Containment limits spread/damage during the incident; preparation happens beforehand." },
  { id:80131, domain:1, level:2, question:"In which phase are the root cause removed and malware deleted from affected systems?", options:["Containment, which only isolates systems to stop the incident from spreading any further","Recovery, which restores systems to normal operation and validates they are fully clean","Eradication, which eliminates the cause of the incident and removes malicious artifacts","Detection, which recognizes and analyzes the indicators that an incident has occurred here"], correct:2, explanation:"Eradication removes the cause/malware; containment only isolates and recovery restores service." },
  { id:80132, domain:1, level:3, question:"An IR team restores systems from clean backups and monitors for reinfection. This is which phase?", options:["Eradication, which removes the malware and underlying cause from the whole environment","Containment, which isolates the affected hosts to prevent the spread of the attack further","Detection and Analysis, which identifies and scopes the incident that has occurred already","Recovery, which returns systems to normal operation and confirms they remain fully clean"], correct:3, explanation:"Restoring service and watching for reinfection is recovery; removing the cause is eradication." },
  { id:80133, domain:1, level:3, question:"Why is the post-incident (lessons learned) phase considered critical to the IR process?", options:["It feeds improvements back into preparation, strengthening the response to future incidents","It is the phase in which the affected systems are first isolated to stop the attack quickly","It is where the incident is initially detected and confirmed as a true security incident now","It replaces the need for a documented incident response plan going forward completely today"], correct:0, explanation:"Lessons learned improve future preparation; it does not detect, isolate, or replace the plan." },
  { id:80134, domain:1, level:2, question:"The EC-Council IH&R process typically begins with which of the following steps?", options:["Incident recording, which logs the details of an already-detected incident thoroughly here","Preparation, which establishes the policies, team, and tools needed before any incidents","Eradication, which removes the malicious cause from the affected systems entirely at once","Post-incident activities, which capture the lessons after the incident is closed and reviewed"], correct:1, explanation:"IH&R begins with preparation; recording and eradication occur later in the process." },
  { id:80135, domain:1, level:3, question:"In the IH&R process, incident triage most directly supports which objective?", options:["Permanently deleting all malware from the network before any analysis is begun at all","Restoring the business operations to their full state before the incident had occurred here","Prioritizing and categorizing incidents so that the most critical ones are handled first","Drafting the organization's long-term information security strategy and its annual budget"], correct:2, explanation:"Triage prioritizes/categorizes incidents; restoration and eradication are separate later steps." },
  { id:80136, domain:1, level:2, question:"Which activity belongs to the Detection and Analysis phase of incident response?", options:["Rebuilding compromised servers from verified clean backup media after cleanup completes","Isolating an infected subnet from the rest of the corporate network immediately at once","Conducting the post-incident review meeting to document the lessons learned afterward","Correlating alerts and logs to confirm whether a reported event is a true incident here"], correct:3, explanation:"Confirming events via correlation is detection/analysis; rebuilding and isolating come later." },
  { id:80137, domain:1, level:1, question:"What is the primary purpose of an incident response policy?", options:["To define the organization's overall approach, authority, and commitment to handling incidents","To list the exact command-line steps an analyst runs to image a hard drive during work","To provide a diagram of the physical network topology for the data center facility layout in this context","To catalog every software license the organization currently owns and actively uses today"], correct:0, explanation:"The policy sets high-level approach and authority; step-by-step commands belong in procedures." },
  { id:80138, domain:1, level:2, question:"How do incident response procedures differ from the incident response policy?", options:["Procedures set the organization's overall intent, while the policy lists the exact steps taken","Procedures give detailed step-by-step actions, while the policy sets the high-level direction","Procedures are optional guidance, while the policy is only advisory and fully non-binding","Procedures apply only to executives, while the policy applies only to frontline analysts"], correct:1, explanation:"Procedures are the detailed steps; the policy provides high-level direction and authority." },
  { id:80139, domain:1, level:2, question:"An incident response plan should, at minimum, define which of the following?", options:["The exact market value of every hardware asset owned by the organization at any time","A complete listing of all employees' personal contact and home address details on file","Roles, responsibilities, communication paths, and procedures for handling incidents","The vendor pricing details for all of the future security product purchases planned soon"], correct:2, explanation:"An IR plan defines roles, responsibilities, communications, and procedures, not asset valuations." },
  { id:80140, domain:1, level:3, question:"Why should an incident response plan be tested and updated regularly?", options:["So that the plan can be submitted once to auditors and then never revisited again at all","So that the organization can eliminate the need for a dedicated incident response team","So that all of the security controls can be permanently disabled during the test window","So that gaps are found and the plan stays effective against evolving threats and changes"], correct:3, explanation:"Regular testing/updates keep the plan effective as threats and environments change." },
  { id:80141, domain:1, level:2, question:"Which document typically contains the criteria used to classify incident severity?", options:["The incident response plan or an associated severity classification and escalation matrix","The organization's annual financial statement filed with the market regulators each year","The vendor's end-user license agreement for the antivirus product currently deployed here","The physical security guard's daily patrol logbook maintained for the whole facility site"], correct:0, explanation:"Severity classification/escalation criteria live in the IR plan; financial filings do not contain them." },
  { id:80142, domain:1, level:1, question:"What does CSIRT stand for in incident response?", options:["Central System Integrity Review Task force that audits configuration baselines routinely","Computer Security Incident Response Team, the group that handles the security incidents","Corporate Security Investigation and Reporting Tool used for case management workflows","Cloud Service Incident Recovery Technology that automates the backup restoration process"], correct:1, explanation:"CSIRT is Computer Security Incident Response Team; the other expansions are fabricated." },
  { id:80143, domain:1, level:2, question:"Which role in an incident response team primarily coordinates the overall response effort?", options:["The forensic analyst, who exclusively collects and examines the digital evidence artifacts","The legal counsel, who only advises on the regulatory and litigation-related matters here","The incident manager or team lead, who directs activities and communications during it","The public relations officer, who solely manages the external media communications work"], correct:2, explanation:"The incident manager/lead coordinates the response; forensics and legal have narrower roles." },
  { id:80144, domain:1, level:2, question:"What is the primary function of a Security Operations Center (SOC)?", options:["Writing all of the organization's application source code and internal business software in this context","Handling the company's payroll processing and human resources record keeping duties","Managing physical building access badges and facility maintenance requests for the site","Continuously monitoring, detecting, and analyzing security events across the organization"], correct:3, explanation:"A SOC monitors, detects, and analyzes security events; it does not write apps or run payroll." },
  { id:80145, domain:1, level:3, question:"Which team model has a central CSIRT that coordinates distributed local teams across sites?", options:["A coordinating or hybrid CSIRT model that links a central team with distributed local ones","A fully centralized model where a single team handles every incident with no delegation in this context","A purely outsourced model where an external provider performs all handling remotely now","A model with no defined team, relying only on individual employees acting ad hoc alone"], correct:0, explanation:"A coordinating/hybrid model links a central team with local teams; the others describe different structures." },
  { id:80146, domain:1, level:1, question:"What is the main purpose of an ISAC (Information Sharing and Analysis Center)?", options:["To certify individual security professionals after they pass a qualifying written exam here in this context","To facilitate sharing of threat intelligence and security information within an industry sector","To manufacture and distribute network security hardware to the member companies cheaply","To provide legal defense services to organizations after a data breach has occurred today"], correct:1, explanation:"ISACs enable sector-based threat information sharing; they do not certify people or make hardware." },
  { id:80147, domain:1, level:2, question:"Sharing indicators of compromise with an industry ISAC primarily helps organizations to:", options:["Transfer all legal liability for any future breaches to the ISAC organization itself entirely","Avoid ever having to build their own internal incident response capability going forward","Benefit from collective threat intelligence and defend proactively against shared threats","Guarantee that they will never experience a successful cyberattack ever again in future"], correct:2, explanation:"ISAC sharing spreads collective threat intelligence; it does not transfer liability or guarantee safety." },
  { id:80148, domain:1, level:3, question:"Which factor is most important when deciding between an in-house and an outsourced CSIRT?", options:["The color scheme chosen for the incident response team's documentation templates in use","The brand of coffee machine installed in the security operations center break room area","The number of parking spaces available at the organization's main headquarters campus","The organization's available expertise, budget, and required response speed and control"], correct:3, explanation:"Expertise, budget, and control/speed drive in-house vs. outsourced decisions; the rest are irrelevant." },
  { id:80149, domain:1, level:2, question:"Which stakeholder should typically be involved when an incident may have legal implications?", options:["Legal counsel, to advise on regulatory obligations, evidence handling, and liability issues","Only the help desk staff, who reset the affected users' account passwords when asked to","Solely the marketing department, which prepares promotional materials for product launch in this context","Exclusively the facilities team, which manages the building heating and cooling systems"], correct:0, explanation:"Legal counsel advises on regulatory and evidentiary matters; help desk and marketing cannot." },
  { id:80150, domain:1, level:1, question:"Who is typically considered a first responder in an information security incident?", options:["The external auditor who reviews controls once a year for compliance purposes on site","The individual who first detects and takes initial action to handle a suspected incident","The vendor sales representative who sold the security appliance to the company earlier in this context","The board member who approves the annual information security budget request each year"], correct:1, explanation:"A first responder first detects and acts on the incident; auditors and vendors do not." },
  { id:80151, domain:1, level:2, question:"Which action should a first responder generally avoid to preserve evidence?", options:["Documenting the current state of the system and the actions being taken very carefully","Notifying the incident response team lead about the suspected security incident promptly in this context","Powering off or rebooting the affected system, which can destroy volatile memory evidence","Isolating the affected system from the network to prevent any further compromise quickly"], correct:2, explanation:"Powering off destroys volatile evidence; documenting, notifying, and isolating are appropriate." },
  { id:80152, domain:1, level:3, question:"Why is maintaining a chain of custody important during first response?", options:["It speeds up the eradication of malware by automatically removing all infected files at once","It eliminates the need to notify management about the security incident occurring at all here","It guarantees the attacker can always be identified and then criminally prosecuted in court","It preserves evidence integrity and admissibility by documenting handling from collection on"], correct:3, explanation:"Chain of custody documents handling to preserve integrity/admissibility; it does not remove malware." },
  { id:80153, domain:1, level:2, question:"During first response, capturing volatile data should generally occur:", options:["Before shutting down the system, because volatile data is lost when the power is removed","After the system has been fully powered off and disconnected from all of its power sources","Only after the entire investigation has been completed and the case is officially closed now","Only if the organization decides much later to pursue criminal prosecution charges in court"], correct:0, explanation:"Volatile data must be captured before shutdown since it is lost on power removal." },
  { id:80154, domain:1, level:1, question:"Which standard specifically provides guidelines for computer security incident handling?", options:["PCI-DSS, which sets requirements for protecting the stored payment cardholder data securely","NIST Special Publication 800-61, the Computer Security Incident Handling Guide document","GDPR, which governs the protection of the personal data of individuals within the EU today","HIPAA, which regulates the privacy and security of protected health information broadly"], correct:1, explanation:"NIST 800-61 is the incident handling guide; PCI-DSS, GDPR, and HIPAA target other domains." },
  { id:80155, domain:1, level:2, question:"Which international standard specifically addresses information security incident management?", options:["ISO 9001, which specifies the requirements for a general quality management system in use","ISO 14001, which sets the requirements for an environmental management system broadly","ISO/IEC 27035, which provides a framework for managing information security incidents","ISO/IEC 20000, which addresses the IT service management practices and service delivery"], correct:2, explanation:"ISO/IEC 27035 covers incident management; 9001 and 14001 address quality and environment." },
  { id:80156, domain:1, level:2, question:"Under GDPR, personal data breaches must generally be reported to the supervisory authority within:", options:["30 days from the end of the calendar month in which the breach initially occurred somewhere","One year following the completion of the full forensic investigation report and its review","24 hours of the affected individuals first noticing suspicious account activity themselves","72 hours of the organization becoming aware of the breach, where feasible to do so at all"], correct:3, explanation:"GDPR requires notification within 72 hours of awareness; the other timelines are incorrect." },
  { id:80157, domain:1, level:2, question:"HIPAA is primarily concerned with protecting which type of information?", options:["Protected health information handled by covered entities and their business associates","Payment card data such as primary account numbers and the card verification values used","Publicly traded companies' financial reporting and internal accounting controls disclosures","Personal data of European Union residents processed by any organization globally today"], correct:0, explanation:"HIPAA protects health information; PCI-DSS covers card data and SOX covers financial reporting." },
  { id:80158, domain:1, level:2, question:"PCI-DSS applies to organizations that:", options:["Handle protected health information for patients within a clinical or hospital setting here","Store, process, or transmit payment cardholder data as part of their normal operations","Process the personal data of European Union residents for essentially any purpose at all","File audited financial statements with the securities market regulators annually each year"], correct:1, explanation:"PCI-DSS governs cardholder data handling; health, EU personal data, and filings fall elsewhere." },
  { id:80159, domain:1, level:1, question:"The Sarbanes-Oxley Act (SOX) primarily focuses on:", options:["The privacy and security safeguards required for protected health information broadly today","The protection of the personal data belonging to European Union data subjects everywhere","Financial reporting accuracy and internal controls for publicly traded companies at large","Technical requirements for securing the stored and transmitted payment card data securely"], correct:2, explanation:"SOX targets financial reporting/internal controls; health, EU data, and card data are others' scope." },
  { id:80160, domain:1, level:3, question:"An organization handling EU customer data and payment cards must comply with which combination?", options:["Only HIPAA, since it broadly covers all forms of sensitive personal information out there","Only SOX, because it regulates every organization that processes any customer data at all","Neither, because non-EU-based companies are fully exempt from all such rules and duties","Both GDPR for personal data protection and PCI-DSS for the payment cardholder data used"], correct:3, explanation:"EU personal data invokes GDPR and cards invoke PCI-DSS; HIPAA and SOX do not apply here." },
  { id:80161, domain:1, level:3, question:"Which framework is best known for its Identify, Protect, Detect, Respond, and Recover functions?", options:["The NIST Cybersecurity Framework, which organizes activities into five core functions overall","ISO/IEC 27035, which specifically defines the phases for the incident management process","The PCI-DSS standard, which lists twelve requirements for the cardholder data security here in this context","The COBIT framework, which focuses primarily on IT governance and its management practices"], correct:0, explanation:"Those five functions define the NIST CSF; ISO 27035 and PCI-DSS have different structures." },
  { id:80162, domain:1, level:1, question:"What is the primary goal of vulnerability management?", options:["To respond to and contain incidents only after a breach has already occurred and spread","To identify, assess, prioritize, and remediate weaknesses before attackers can exploit them","To prosecute attackers in court after the evidence of an intrusion is finally collected here","To market the organization's strong security posture to prospective new customers publicly"], correct:1, explanation:"Vulnerability management proactively finds and fixes weaknesses; responding after a breach is IR." },
  { id:80163, domain:1, level:2, question:"Which activity is a core component of the vulnerability management life cycle?", options:["Encrypting all outbound email so that competitors cannot read any of the messages sent","Physically shredding printed documents once they are no longer needed by the staff at all in this context","Regularly scanning systems to discover known vulnerabilities and tracking their remediation","Negotiating the annual price of the organization's cyber insurance policy with the broker"], correct:2, explanation:"Recurring scanning and remediation tracking is core to vulnerability management; the rest are not." },
  { id:80164, domain:1, level:2, question:"Risk assessment primarily helps an organization to:", options:["Guarantee that no security incident will ever affect the organization again in the future","Eliminate every single vulnerability in the environment regardless of its cost or impact","Replace the need for both an incident response plan and a dedicated response team here","Identify and prioritize risks so resources can be focused on the most significant ones"], correct:3, explanation:"Risk assessment prioritizes risks for resource focus; it cannot guarantee zero incidents." },
  { id:80165, domain:1, level:3, question:"Which risk treatment option involves purchasing cyber insurance to offset potential losses?", options:["Risk transfer, which shifts a portion of the financial impact to a third party externally","Risk avoidance, which eliminates the activity that gives rise to the risk entirely and fully","Risk acceptance, which acknowledges the risk and then takes no additional action at all now","Risk mitigation, which reduces the likelihood or the impact through the added controls used"], correct:0, explanation:"Insurance is risk transfer; avoidance stops the activity and mitigation reduces likelihood/impact." },
  { id:80166, domain:1, level:3, question:"An organization decides a low-impact risk is not worth the cost of additional controls. This is:", options:["Risk mitigation, in which the additional controls reduce the likelihood or the impact seen","Risk acceptance, in which the organization knowingly tolerates the residual risk that remains","Risk transfer, in which the potential loss is shifted to an insurer or a partner externally in this context","Risk avoidance, in which the risky activity is discontinued altogether to remove it fully"], correct:1, explanation:"Knowingly tolerating a residual risk is acceptance; mitigation would add controls." },
  { id:80167, domain:1, level:2, question:"What distinguishes a vulnerability assessment from a penetration test?", options:["A vulnerability assessment exploits flaws, while a pen test only lists the potential ones","A vulnerability assessment is always illegal, while a pen test is always fully authorized","A vulnerability assessment identifies weaknesses, while a pen test actively exploits them","A vulnerability assessment tests only hardware, while a pen test tests only the software"], correct:2, explanation:"Vulnerability assessment identifies weaknesses; a pen test goes further and exploits them." },
  { id:80168, domain:1, level:1, question:"Which of the following best defines an information security event?", options:["A confirmed malicious act that has already caused measurable damage to the organization","A formal written policy describing how staff should handle a declared incident correctly","A control that is deliberately implemented to reduce the risk to a protected asset today","An observed occurrence in a system or network that may be relevant to security posture"], correct:3, explanation:"An event is any observed occurrence; a confirmed harmful occurrence is an incident, not an event." },
  { id:80169, domain:1, level:2, question:"How does a security incident differ from a security event?", options:["An incident is an event or series of events that actually harm or threaten security here","An incident is a control while an event is the observed occurrence detected on the network","An incident is always benign while an event always causes damage to the affected systems","An incident occurs only in the cloud while an event occurs only on on-premises hardware"], correct:0, explanation:"An incident is a harmful or threatening event/series; not every event becomes an incident." },
  { id:80170, domain:1, level:2, question:"A botnet is best described as:", options:["A single infected host that repeatedly scans one target for open ports over many hours","A network of compromised computers controlled remotely by an attacker to act together","A legitimate content delivery network used to speed up static web page loading globally","A hardware appliance placed at the perimeter to filter inbound and outbound traffic flows"], correct:1, explanation:"A botnet is many compromised hosts under remote control; a single host or a CDN is not a botnet." },
  { id:80171, domain:1, level:1, question:"A trojan horse is malware that:", options:["Self-replicates across the network automatically without any user interaction at all here","Encrypts the victim's files and then demands a ransom payment to release the data back","Disguises itself as legitimate software to trick a user into installing and running it","Floods a target server with traffic from many hosts to exhaust its available resources"], correct:2, explanation:"A trojan masquerades as legitimate software; self-replication describes a worm, not a trojan." },
  { id:80172, domain:1, level:2, question:"Which attack captures data by intercepting communications between two parties?", options:["A denial-of-service attack, which floods the target to make its service unavailable to users","A privilege escalation attack, which raises the attacker's rights on a compromised system","A password spraying attack, which tries one common password across many user accounts","A man-in-the-middle attack, which secretly relays and possibly alters the exchanged data"], correct:3, explanation:"MITM intercepts communications between parties; DoS and password spraying attack differently." },
  { id:80173, domain:1, level:3, question:"Which of the following best characterizes an advanced persistent threat (APT)?", options:["A stealthy, prolonged, and targeted intrusion often by a well-resourced adversary group","A single opportunistic malware infection that is quickly detected and removed the same day","An automated vulnerability scan that briefly probes a public website for open services","A routine phishing email blasted to millions of random recipients with no specific target"], correct:0, explanation:"An APT is a stealthy, sustained, targeted campaign; a one-off scan or blast is not an APT." },
  { id:80174, domain:1, level:2, question:"What is the main purpose of incident categorization?", options:["To permanently delete the incident records so that auditors cannot review them again later","To group incidents by type so appropriate handling procedures and resources can be applied","To immediately assign legal blame to a specific employee before any investigation begins","To calculate the exact monetary value of every asset owned across the whole organization"], correct:1, explanation:"Categorization groups incidents by type to guide handling; it does not assign blame or delete records." },
  { id:80175, domain:1, level:2, question:"Incident prioritization is primarily based on which of the following?", options:["The alphabetical order of the affected system hostnames listed in the asset inventory","The personal preference of whichever analyst happens to pick up the ticket that day","The functional and information impact of the incident and its recoverability effort needed","The physical distance between the affected server and the security operations center desk in this context"], correct:2, explanation:"Prioritization weighs functional/informational impact and recoverability; hostname order is irrelevant." },
  { id:80176, domain:1, level:1, question:"What is the role of escalation in incident handling?", options:["To immediately shut down all systems in the organization whenever any alert is triggered","To delete evidence quickly so that the incident does not appear in any compliance report","To reward the analyst who first reported the incident with an automatic financial bonus","To involve higher-level personnel or teams when an incident exceeds the current capacity"], correct:3, explanation:"Escalation brings in higher authority/resources when needed; it does not delete evidence or reward staff." },
  { id:80177, domain:1, level:2, question:"Which of the following is a key benefit of documenting incidents thoroughly?", options:["It supports lessons learned, legal needs, and future response improvement over time","It removes the requirement to ever notify affected customers about a breach at any point","It guarantees that the same type of incident can never possibly occur again in the future","It allows the organization to legally avoid all regulatory reporting obligations entirely"], correct:0, explanation:"Documentation aids lessons learned, legal, and improvement; it does not remove notification duties." },
  { id:80178, domain:1, level:3, question:"Why is establishing communication procedures important before an incident occurs?", options:["So the organization can avoid ever having to speak with law enforcement about incidents","So responders know who to notify and how, avoiding confusion and delay during a crisis","So that all incident details can be posted publicly on social media as they are discovered","So that the incident response plan itself becomes unnecessary once staff are all trained"], correct:1, explanation:"Predefined communications prevent confusion/delay; they do not replace the plan or force public posting." },
  { id:80179, domain:1, level:2, question:"Which of the following describes a zero-day vulnerability?", options:["A weakness that was patched years ago but remains on some poorly maintained systems","A configuration error introduced by an administrator that is fixed within the same day","A flaw unknown to the vendor for which no patch is yet available when it is exploited","A vulnerability that exists only in theory and can never actually be exploited in practice"], correct:2, explanation:"A zero-day is unknown to the vendor with no patch yet; a long-patched flaw is not a zero-day." },
  { id:80180, domain:1, level:1, question:"What is spear phishing?", options:["A mass email sent to millions of random recipients hoping a small fraction respond at all","A physical attack in which an intruder tailgates an employee through a secured door lock","A flood of network packets designed to overwhelm a target server until it stops responding in this context","A targeted phishing attack aimed at a specific individual or organization using tailored details"], correct:3, explanation:"Spear phishing is targeted and tailored; a mass untargeted blast is ordinary phishing." },
  { id:80181, domain:1, level:2, question:"Whaling is a form of social engineering that specifically targets:", options:["High-profile executives or senior leaders because of their access and authority in the firm","Entry-level interns because they typically have the weakest passwords in the organization in this context","Automated service accounts that run scheduled batch jobs on the backend servers nightly","Random members of the public who have no relationship with the targeted organization"], correct:0, explanation:"Whaling targets high-value executives; interns and service accounts are not the whaling focus." },
  { id:80182, domain:1, level:2, question:"Which of the following is an example of a physical security incident?", options:["A phishing email tricks a remote user into entering credentials on a fake login web page in this context","An unauthorized person tailgates through a badge-controlled door into a secure server room","A SQL injection payload extracts customer records from a public-facing web application","A worm spreads laterally across the internal network by exploiting an unpatched service"], correct:1, explanation:"Tailgating into a secure area is a physical incident; phishing, SQLi, and worms are logical attacks." },
  { id:80183, domain:1, level:3, question:"An organization notices reconnaissance scans followed by exploitation attempts. This progression maps to:", options:["The recovery phase of incident response, where systems are restored from clean backups","The lessons-learned phase, where the team documents improvements for future incidents","Early stages of an attack lifecycle, from reconnaissance toward exploitation of a target","The risk acceptance decision, where a low-impact risk is knowingly tolerated without action"], correct:2, explanation:"Scanning then exploiting reflects early attack lifecycle stages, not IR recovery or risk decisions." },
  { id:80184, domain:1, level:2, question:"What is the primary purpose of a runbook or playbook in incident response?", options:["To store the encrypted backups of every server that the organization currently operates","To list the salaries of all incident response team members for budgeting purposes yearly","To advertise the organization's security services to potential clients and new partners","To provide predefined step-by-step guidance for handling a specific type of incident"], correct:3, explanation:"A playbook gives repeatable steps for a scenario; it is not a backup store or a sales tool." },
  { id:80185, domain:1, level:1, question:"Which of the following best describes threat intelligence?", options:["Evidence-based knowledge about threats used to inform defensive decisions and actions","A single antivirus signature that detects one specific known malware file on a host","The physical inventory of all laptops and desktops assigned to employees in the company","A legal contract that transfers breach liability from the organization to an insurer firm"], correct:0, explanation:"Threat intelligence is actionable, evidence-based threat knowledge; one signature is not intelligence." },
  { id:80186, domain:1, level:2, question:"Tactical threat intelligence is most useful for which audience?", options:["Board members who only need a high-level annual summary of the overall risk landscape","SOC analysts and responders who need indicators and TTPs to detect and block threats","Marketing staff who craft public messaging about the company's security achievements","Facilities managers who plan the physical layout of the data center cooling systems used"], correct:1, explanation:"Tactical intel (IOCs, TTPs) serves analysts/responders; board-level summaries are strategic intel." },
  { id:80187, domain:1, level:2, question:"Which of the following is a common goal of the containment strategy selection?", options:["Ensuring that every affected system is permanently destroyed regardless of business need","Guaranteeing that no evidence is ever collected so the investigation cannot be reopened","Balancing the need to limit damage against the need to preserve evidence and operations","Automatically notifying the public before the incident scope has even been determined yet"], correct:2, explanation:"Containment balances damage limitation with evidence preservation and business continuity." },
  { id:80188, domain:1, level:3, question:"Why might an organization choose delayed containment for a specific incident?", options:["To ensure the attacker is never identified so that no legal action can ever be pursued","To avoid documenting the incident so that it does not appear in compliance audits later","To guarantee that the affected systems can never be recovered or restored afterward at all","To observe attacker behavior and gather more evidence before cutting off their access"], correct:3, explanation:"Delayed containment can gather intelligence/evidence; it is not about avoiding documentation or recovery." },
  { id:80189, domain:1, level:1, question:"What is the purpose of an acceptable use policy (AUP)?", options:["To define how employees may use organizational systems and what conduct is prohibited","To list the exact forensic tools used by the incident response team during an investigation","To calculate the annual depreciation of all IT hardware assets for accounting purposes","To store the master encryption keys that protect all of the organization's backups securely"], correct:0, explanation:"An AUP defines permitted system use and prohibited conduct; it is not a forensic tool list." },
  { id:80190, domain:1, level:2, question:"Which of the following is an insider threat indicator?", options:["A firewall automatically blocking known malicious IP addresses per its configured rules in this context","An employee accessing large volumes of sensitive data unrelated to their normal job role","A scheduled patch being deployed to servers during an approved maintenance window","A user completing mandatory annual security awareness training on the assigned deadline"], correct:1, explanation:"Unusual bulk access outside one's role suggests insider threat; routine patching and training do not." },
  { id:80191, domain:1, level:2, question:"What distinguishes a malicious insider from a negligent insider?", options:["A malicious insider is always external, while a negligent insider is always a full-time employee","A malicious insider never has access, while a negligent insider has full administrator rights","A malicious insider intends harm, while a negligent insider causes harm through carelessness","A malicious insider only exists in theory, while a negligent insider is the only real threat"], correct:2, explanation:"Malicious insiders act with intent; negligent insiders cause harm unintentionally through carelessness." },
  { id:80192, domain:1, level:3, question:"An email demands gift card purchases while impersonating the CEO. This best illustrates:", options:["A distributed denial-of-service attack that overwhelms the mail server with junk traffic","A cross-site scripting attack that runs a malicious script inside the recipient's web browser in this context","A brute-force attack that systematically guesses the CEO's email account password overnight","Business email compromise using social engineering and authority to induce a fraudulent action"], correct:3, explanation:"CEO impersonation to induce payment is business email compromise; DDoS and XSS are unrelated attacks." },
  { id:80193, domain:1, level:1, question:"What is the primary purpose of security awareness training?", options:["To educate staff so they can recognize and avoid common threats like phishing attempts","To replace the need for any technical security controls such as firewalls or antivirus tools","To ensure that only the IT department is ever held responsible for any security incident","To automatically patch all vulnerabilities across every endpoint in the organization daily"], correct:0, explanation:"Awareness training reduces human-factor risk; it does not replace technical controls or auto-patch." },
  { id:80194, domain:1, level:2, question:"Which of the following is true about defense in depth?", options:["It relies on a single strong control such as a firewall to block all possible attacks alone","It layers multiple controls so that if one fails, others still protect the asset in question","It removes the need for monitoring because layered controls stop every threat automatically","It applies only to physical security and has no relevance to network or host defenses at all"], correct:1, explanation:"Defense in depth layers controls for redundancy; relying on a single control contradicts the concept." },
  { id:80195, domain:1, level:2, question:"What is the purpose of a service level agreement (SLA) in incident response?", options:["To transfer all legal liability for breaches from the provider to the customer permanently","To store the forensic evidence collected during every incident for regulatory review later","To define expected response and resolution times so expectations are clear and measurable","To list every vulnerability discovered on the network along with its remediation deadline"], correct:2, explanation:"An SLA sets response/resolution expectations; it is not an evidence store or liability transfer." },
  { id:80196, domain:1, level:3, question:"Which statement best captures the relationship between threats, vulnerabilities, and risk?", options:["Risk exists only when there are no vulnerabilities present anywhere in the environment at all","A vulnerability with no corresponding threat automatically produces the highest possible risk","Threats and vulnerabilities are identical terms that both mean the same thing in practice","Risk arises when a threat can exploit a vulnerability, producing potential impact to an asset"], correct:3, explanation:"Risk emerges when a threat can exploit a vulnerability with impact; the terms are not identical." },
  { id:80197, domain:1, level:2, question:"Which of the following is an administrative security control?", options:["A security policy that governs how staff must handle sensitive data and report incidents","A firewall appliance that filters inbound and outbound traffic based on configured rules","A biometric scanner installed at the data center entrance to verify authorized personnel","An intrusion detection sensor that inspects network packets for known attack signatures"], correct:0, explanation:"A policy is an administrative control; firewalls, scanners, and IDS are technical or physical controls." },
  { id:80198, domain:1, level:1, question:"What is the main goal of a business continuity plan (BCP)?", options:["To identify and exploit vulnerabilities in the organization's public-facing web applications in this context","To keep critical business functions operating or quickly resumed during and after a disruption","To catalog every phishing email received by employees over the course of a calendar year","To transfer all cybersecurity responsibilities to an external managed service provider fully"], correct:1, explanation:"A BCP sustains/resumes critical functions during disruption; it is not a vulnerability exploitation tool." },
  { id:80199, domain:1, level:2, question:"How does a disaster recovery plan (DRP) relate to a business continuity plan (BCP)?", options:["A DRP fully replaces the BCP because IT recovery is the only concern during a disruption","A DRP applies only to physical fires while a BCP applies only to cyber incidents alone","A DRP focuses on restoring IT systems, forming a subset of the broader continuity effort","A DRP and a BCP are unrelated documents that never reference each other in any scenario"], correct:2, explanation:"A DRP restores IT and supports the broader BCP; it does not replace it or address only fires." },
  { id:80200, domain:1, level:3, question:"During which situation would law enforcement most appropriately be engaged in an incident?", options:["Whenever any routine antivirus alert fires on a single workstation during normal operations in this context","Only after the organization has fully recovered and closed the incident with no open items","Never, because involving law enforcement always violates data protection laws automatically","When a serious crime such as major data theft or extortion warrants an official investigation"], correct:3, explanation:"Law enforcement suits serious crimes like extortion; routine alerts do not warrant their involvement." },
  { id:80201, domain:1, level:2, question:"What is the primary purpose of network segmentation as a security control?", options:["To limit lateral movement so a compromise in one segment does not spread across the network","To increase overall bandwidth by combining all subnets into one large flat broadcast domain","To eliminate the need for firewalls because segmented networks are inherently attack-proof","To store all backup data in a single central location for faster restoration during outages"], correct:0, explanation:"Segmentation limits lateral movement and contains compromise; it does not make firewalls unnecessary." },
  { id:80202, domain:1, level:1, question:"What does the principle of least privilege require?", options:["Giving every user full administrator rights to reduce the number of help desk tickets filed","Granting users only the access rights necessary to perform their specific job functions","Sharing a single privileged account among all staff so that access is simple to manage","Removing all access controls so that employees can collaborate without any restrictions"], correct:1, explanation:"Least privilege grants only necessary access; broad admin rights and shared accounts violate it." },
  { id:80203, domain:1, level:2, question:"Which of the following best describes multi-factor authentication?", options:["Requiring a single very long and complex password that is rotated every ninety days regularly","Allowing access based solely on the source IP address of the connecting client machine","Requiring two or more independent factors such as a password and a one-time token to log in","Verifying identity only through a security question answered during the account creation"], correct:2, explanation:"MFA combines independent factors; a single long password or IP check is still one factor." },
  { id:80204, domain:1, level:2, question:"What is the purpose of a security information and event management (SIEM) system?", options:["To automatically write and deploy patches for every vulnerability found across the network in this context","To physically control which employees may enter the building using badge readers at doors","To replace the incident response team by fully automating all decisions during an incident","To aggregate and correlate logs from many sources to detect and investigate security events"], correct:3, explanation:"A SIEM aggregates and correlates logs for detection/investigation; it does not patch or replace the team." },
  { id:80205, domain:1, level:3, question:"Why is time synchronization across systems important for incident investigation?", options:["Accurate correlated timestamps let investigators reconstruct the sequence of events reliably","Synchronized clocks automatically block attackers from accessing any system on the network","Time synchronization encrypts all log files so that attackers cannot read or alter them later","It removes the need to collect logs because synchronized systems never generate incidents"], correct:0, explanation:"Synchronized clocks enable reliable event correlation; they do not encrypt logs or block attackers." },
  { id:80206, domain:1, level:1, question:"What is a honeypot used for in security operations?", options:["A backup server that stores encrypted copies of all production data for disaster recovery in this context","A decoy system designed to attract attackers so their behavior can be observed and studied","A firewall rule set that permanently blocks every inbound connection from the internet","A password manager that securely stores credentials for the entire organization centrally"], correct:1, explanation:"A honeypot is a decoy to lure and study attackers; it is not a backup or a firewall rule set." },
  { id:80207, domain:1, level:2, question:"Which of the following describes credential stuffing?", options:["Injecting malicious SQL statements into a login form to bypass authentication on a website","Flooding an authentication server with traffic from many hosts to make it unavailable to users","Using username and password pairs stolen from one breach to attempt logins on other services","Encrypting a victim's stored password database and demanding payment to decrypt it back"], correct:2, explanation:"Credential stuffing reuses breached credentials across sites; SQL injection and DoS are different attacks." },
  { id:80208, domain:1, level:2, question:"What is the main risk associated with shadow IT?", options:["Sanctioned systems become too heavily monitored, slowing down all legitimate business work","Approved software receives too many security patches, causing frequent unplanned downtime","Central IT gains complete visibility into every device, eliminating the need for any policy in this context","Unsanctioned systems and services operate outside security oversight, creating hidden exposure"], correct:3, explanation:"Shadow IT creates unmonitored exposure outside oversight; it does not increase central visibility." },
  { id:80209, domain:1, level:3, question:"An organization wants to detect anomalies based on deviations from normal behavior. This describes:", options:["Behavior-based or anomaly detection, which flags activity that deviates from an established baseline","Signature-based detection, which matches traffic only against a list of known attack patterns in this context","Physical access control, which restricts entry to secure areas using badges and biometrics","Data classification, which labels information according to its sensitivity level for handling"], correct:0, explanation:"Detecting deviations from a baseline is anomaly-based detection; signatures match known patterns only." },
  { id:80210, domain:1, level:1, question:"What is the purpose of data classification?", options:["To permanently delete all data that is older than a fixed number of years across the company","To label information by sensitivity so that appropriate protection and handling can be applied","To combine every dataset into one shared repository accessible to all employees without limits","To measure the physical size of files so that storage capacity can be planned more easily"], correct:1, explanation:"Classification labels data by sensitivity to drive protection; it is not about deletion or file size." },
  { id:80211, domain:1, level:2, question:"Which of the following is an example of a technical (logical) security control?", options:["A written incident response policy approved and signed off by the executive leadership team","A locked cabinet that physically secures sensitive paper records inside the records room","An intrusion prevention system that inspects and blocks malicious traffic on the network","A background check performed on new employees before they are granted system access"], correct:2, explanation:"An IPS is a technical control; policies are administrative and locks/checks are physical or administrative." },
  { id:80212, domain:1, level:2, question:"What is the primary function of endpoint detection and response (EDR)?", options:["To provide high-speed internet connectivity to remote branch offices over encrypted tunnels","To manage the physical inventory of laptops and desktops assigned across the organization","To generate marketing analytics from website visitor behavior for the sales department","To monitor endpoints for suspicious activity and enable investigation and response actions"], correct:3, explanation:"EDR monitors endpoints and enables response; it is not a connectivity or inventory tool." },
  { id:80213, domain:1, level:3, question:"Why is asset inventory important to effective incident response?", options:["Knowing what assets exist and their value helps responders scope, prioritize, and protect them","A complete inventory guarantees that no asset can ever be compromised by any attacker again","Maintaining an inventory removes the requirement to monitor or patch any of the listed systems","Asset inventory is used only by the finance team and has no bearing on security operations"], correct:0, explanation:"Inventory enables scoping and prioritization during response; it does not make assets uncompromisable." },
  { id:80214, domain:1, level:1, question:"What does non-repudiation provide in information security?", options:["Assurance that data remains secret and is disclosed only to those who are authorized to see it in this context","Assurance that a party cannot deny having performed an action, supported by verifiable evidence","Assurance that systems remain available to authorized users whenever they need to access them","Assurance that all network traffic is encrypted end to end between the two communicating hosts"], correct:1, explanation:"Non-repudiation prevents denial of an action via evidence; secrecy and uptime are other properties." },
  { id:80215, domain:1, level:2, question:"Which of the following best describes lateral movement in an attack?", options:["An attacker sending a single phishing email to every employee in the organization at once","An external scan that enumerates open ports on a public-facing server before any intrusion in this context","An attacker pivoting from one compromised system to reach additional systems within the network","A user resetting a forgotten password through the approved self-service recovery portal"], correct:2, explanation:"Lateral movement is pivoting to more internal systems; a scan or phishing blast is not lateral movement." },
  { id:80216, domain:1, level:2, question:"What is the purpose of a demilitarized zone (DMZ) in network architecture?", options:["To store all sensitive customer records in the most exposed segment for faster public access in this context","To eliminate the need for any firewall between the internal network and the public internet","To provide a physical break room area for the security operations center staff during shifts","To host public-facing services in a buffer segment that isolates them from the internal network"], correct:3, explanation:"A DMZ isolates public-facing services from the internal network; it does not store sensitive data openly." },
  { id:80217, domain:1, level:3, question:"An attacker gains higher access rights after compromising a low-privileged account. This is:", options:["Privilege escalation, in which an attacker increases their rights beyond what was granted","Data exfiltration, in which stolen information is transferred out of the organization to attackers","Denial of service, in which the targeted system is made unavailable to its legitimate users","Reconnaissance, in which the attacker only gathers information without accessing any system"], correct:0, explanation:"Gaining higher rights is privilege escalation; exfiltration and DoS describe different attack outcomes." },
  { id:80218, domain:1, level:1, question:"What is the main purpose of a firewall?", options:["To scan endpoints for viruses and quarantine any malicious files that are discovered locally","To control network traffic by allowing or blocking it based on a defined set of rules","To back up critical data automatically so that it can be restored after a disaster event","To train employees to recognize and report phishing emails they receive in their inboxes"], correct:1, explanation:"A firewall filters traffic per rules; antivirus scanning and backups are separate functions." },
  { id:80219, domain:1, level:2, question:"Which of the following is a hallmark of ransomware behavior on an endpoint?", options:["Silent forwarding of every outbound email to an external address without altering any local files","Gradual slowing of the network as traffic is relayed through an attacker-controlled proxy server","Rapid encryption of many files followed by a ransom note demanding payment for the decryption key","Automatic installation of legitimate vendor patches during the approved maintenance window"], correct:2, explanation:"Mass file encryption plus a ransom note is classic ransomware; email forwarding is a different threat." },
  { id:80220, domain:1, level:2, question:"What is the purpose of a data loss prevention (DLP) solution?", options:["To accelerate database queries by caching frequently accessed records in fast local memory in this context","To physically shred paper documents once their required retention period has fully elapsed","To manage employee vacation schedules and coordinate coverage across the support teams","To detect and prevent unauthorized transfer of sensitive data outside the organization's boundary"], correct:3, explanation:"DLP detects/prevents unauthorized sensitive-data exfiltration; it is not a caching or shredding tool." },
  { id:80221, domain:1, level:3, question:"Why should organizations maintain and review audit logs continuously?", options:["Logs provide the evidence needed to detect, investigate, and reconstruct security incidents accurately","Reviewing logs guarantees that attackers will be unable to compromise any system in the future","Continuous logging automatically remediates every vulnerability discovered on the monitored hosts in this context","Audit logs replace the need for both an incident response plan and a trained response team"], correct:0, explanation:"Logs enable detection and reconstruction; they do not remediate vulnerabilities or replace the plan." },
  { id:80222, domain:1, level:1, question:"What is an exploit in the context of information security?", options:["A written policy that describes how the organization handles confirmed security incidents","Code or a technique that takes advantage of a vulnerability to cause unintended behavior","A backup copy of critical data stored offsite for use during a disaster recovery scenario","A control implemented to reduce the likelihood that a threat can reach a protected asset"], correct:1, explanation:"An exploit leverages a vulnerability; a policy, backup, or control is not itself an exploit." },
  { id:80223, domain:1, level:2, question:"Which of the following best describes a false positive in security monitoring?", options:["A real attack that the monitoring system completely fails to detect or alert on at all","A confirmed incident that is correctly identified and escalated to the response team promptly in this context","An alert that flags benign activity as malicious when no actual security incident has occurred","A scheduled maintenance task that is intentionally excluded from all monitoring dashboards"], correct:2, explanation:"A false positive flags benign activity as malicious; a missed real attack is a false negative." },
  { id:80224, domain:1, level:2, question:"What distinguishes a false negative from a false positive?", options:["A false negative flags benign activity, while a false positive misses a genuine ongoing attack","A false negative and a false positive both mean the monitoring system is functioning perfectly","A false negative occurs only in firewalls, while a false positive occurs only in antivirus tools","A false negative misses a real attack, while a false positive flags benign activity as an attack"], correct:3, explanation:"A false negative misses a real attack; a false positive incorrectly flags benign activity." },
  { id:80225, domain:1, level:3, question:"An organization maps observed attacker techniques to a knowledge base of tactics. This best describes use of:", options:["A structured framework like MITRE ATT&CK to categorize adversary tactics and techniques","A financial ledger used to track the annual depreciation of all owned IT hardware assets","A physical floor plan showing the placement of badge readers throughout the office building","A marketing funnel that measures how website visitors convert into paying new customers"], correct:0, explanation:"Mapping techniques to tactics uses a framework like MITRE ATT&CK; the others are unrelated tools." },
  { id:80226, domain:1, level:1, question:"What is the purpose of patch management?", options:["To permanently archive old software versions so they can be reinstalled at any later time","To apply updates that fix vulnerabilities and reduce the window of exposure to known threats","To measure how much disk space each installed application consumes on a given endpoint","To advertise newly released features of vendor software to end users through pop-up alerts in this context"], correct:1, explanation:"Patch management fixes vulnerabilities to reduce exposure; it is not an archival or advertising function." },
  { id:80227, domain:1, level:2, question:"Which of the following is a key characteristic of a well-defined incident classification scheme?", options:["It assigns every incident to the highest severity level regardless of the actual measured impact","It relies on each analyst inventing new category names for every incident they encounter daily","It uses consistent categories so incidents are handled uniformly and prioritized appropriately","It classifies incidents only after they are fully resolved so no handling decisions depend on it"], correct:2, explanation:"Consistent categories enable uniform handling and prioritization; ad hoc naming undermines the scheme." },
  { id:80228, domain:1, level:2, question:"What is the purpose of a tabletop exercise in incident response preparation?", options:["To physically rebuild every production server from backups to test the recovery procedures live","To permanently disable all security controls so the team can practice responding without any alerts","To calculate the exact monetary loss the organization would suffer from a specific real breach","To walk through a simulated incident scenario and evaluate the plan, roles, and decisions together"], correct:3, explanation:"A tabletop simulates a scenario to test the plan and roles; it does not disable controls or rebuild servers." },
  { id:80229, domain:1, level:3, question:"Why is defining incident response roles in advance especially valuable during a major incident?", options:["Clear predefined roles reduce confusion and duplicated effort so the team can act quickly and coordinated","Predefined roles guarantee that the incident will be resolved without any need for escalation ever","Assigning roles early ensures that no documentation or evidence will need to be collected later","Defined roles allow the organization to skip the preparation phase of the response lifecycle entirely in this context"], correct:0, explanation:"Predefined roles cut confusion and speed coordinated action; they do not remove escalation or documentation." },
  { id:80230, domain:1, level:1, question:"What is social engineering in the context of security incidents?", options:["Reconfiguring network hardware to route traffic more efficiently across multiple data centers","Manipulating people into divulging information or performing actions that compromise security","Writing secure application code that validates all user input before processing it on the server","Encrypting data at rest so that stolen storage media cannot be read by an unauthorized party"], correct:1, explanation:"Social engineering manipulates people psychologically; the others are technical, not human, techniques." },
  { id:80231, domain:1, level:2, question:"Which of the following is an example of pretexting?", options:["An attacker floods a target website with traffic from thousands of compromised devices at once in this context","An attacker injects a malicious script into a vulnerable web page to run in visitors' browsers","An attacker invents a believable scenario, such as posing as IT support, to obtain sensitive information","An attacker guesses common passwords rapidly against a login portal until one finally works"], correct:2, explanation:"Pretexting uses a fabricated scenario to extract information; the others are DoS, XSS, and brute force." },
  { id:80232, domain:1, level:2, question:"What is baiting as a social engineering technique?", options:["Sending a single email to millions of random recipients hoping a few will reply with details","Intercepting and altering messages passing between two parties without either one noticing it","Overwhelming a server with requests until it becomes unavailable to its legitimate users","Luring a victim with an enticing item, such as an infected USB drive, to trigger a compromise"], correct:3, explanation:"Baiting entices victims with a tempting item like a malicious USB; the others describe different attacks." },
  { id:80233, domain:1, level:3, question:"An analyst must decide whether an alert represents a genuine incident before escalating. This step is part of:", options:["Incident validation and analysis, which confirms whether a reported event is truly an incident","The eradication phase, in which the malicious root cause is removed from all affected systems","The recovery phase, in which systems are restored to normal operation from clean backup media","The preparation phase, in which the team assembles tools and policies before any incident occurs"], correct:0, explanation:"Confirming whether an event is a true incident is validation/analysis, not eradication or recovery." },
  { id:80234, domain:1, level:1, question:"What is the purpose of an intrusion detection system (IDS)?", options:["To automatically block all inbound traffic from the internet without generating any alerts","To monitor network or host activity and alert on suspicious or malicious behavior it detects","To encrypt sensitive files stored on endpoints so that stolen devices reveal no readable data","To manage user accounts and enforce password complexity requirements across the enterprise"], correct:1, explanation:"An IDS detects and alerts on suspicious activity; blocking is done by an IPS or firewall, not a pure IDS." },
  { id:80235, domain:1, level:2, question:"How does an intrusion prevention system (IPS) differ from an intrusion detection system (IDS)?", options:["An IPS only logs events for later review, while an IDS automatically blocks all detected threats","An IPS works only on wireless networks, while an IDS works only on physical wired connections","An IPS can actively block or drop malicious traffic, while an IDS only detects and alerts on it","An IPS and an IDS are identical and the two terms are fully interchangeable in every context"], correct:2, explanation:"An IPS actively blocks malicious traffic; an IDS only detects and alerts without blocking." },
  { id:80236, domain:1, level:2, question:"What is the primary benefit of encrypting sensitive data at rest?", options:["Encrypted data can never be accidentally deleted or corrupted by any system failure ever again","Encryption automatically detects and blocks all incoming network attacks against the host system","Encrypting data removes the requirement to control who is authorized to access that data at all","Stolen or lost storage media remain unreadable to anyone without the correct decryption key"], correct:3, explanation:"Encryption at rest protects confidentiality if media is stolen; it does not block network attacks." },
  { id:80237, domain:1, level:3, question:"Why is separation of duties an important security principle in incident handling and operations?", options:["It prevents any single individual from controlling a whole process, reducing fraud and error risk","It ensures one trusted employee handles every step alone so accountability is fully centralized","It removes the need for logging because divided duties automatically prevent all misconduct","It applies only to physical security guards and has no relevance to any IT or security processes in this context"], correct:0, explanation:"Separation of duties prevents unilateral control, reducing fraud/error; centralizing in one person is the opposite." },
  { id:80238, domain:1, level:1, question:"What is threat modeling used for?", options:["To measure the exact physical dimensions of the data center for cooling and power planning in this context","To systematically identify potential threats and weaknesses so defenses can be prioritized early","To catalog every marketing campaign the organization has run over the previous five years","To automatically apply software patches to all endpoints as soon as vendors release them"], correct:1, explanation:"Threat modeling identifies and prioritizes potential threats/weaknesses; it is not a patching tool." },
  { id:80239, domain:1, level:2, question:"Which of the following best describes a supply chain attack?", options:["Flooding a single target with traffic from many hosts to make its services unavailable to users in this context","Guessing a user's password by trying many common combinations against the login page quickly","Compromising a trusted vendor or component to reach the vendor's downstream customers indirectly","Sending a fraudulent email that impersonates a bank to trick a recipient into paying money"], correct:2, explanation:"A supply chain attack compromises a trusted supplier to reach customers; the others are DoS, brute force, and phishing." },
  { id:80240, domain:1, level:2, question:"What is the main purpose of a security policy exception process?", options:["To allow any employee to ignore any security policy at will without any oversight or record kept","To permanently delete outdated policies so that they no longer apply to anyone in the company","To automatically escalate every routine alert directly to the executive leadership team each time in this context","To formally review, document, and approve deviations from policy while managing the associated risk"], correct:3, explanation:"An exception process formally reviews and documents policy deviations with risk management, not free waivers." },
  { id:80241, domain:1, level:3, question:"An organization wants attackers who breach the perimeter to still face further obstacles internally. This goal aligns with:", options:["A zero trust or defense-in-depth approach that verifies and restricts access at multiple internal layers","A single perimeter firewall assumed to be sufficient because internal traffic is inherently trusted in this context","Disabling all internal authentication so that employees can move freely once inside the network","Publishing all internal system credentials so support staff never need to request access again"], correct:0, explanation:"Zero trust/defense in depth restricts access at internal layers; trusting all internal traffic is the opposite." },
  { id:80242, domain:1, level:1, question:"What is the purpose of an antivirus or anti-malware solution?", options:["To encrypt all network traffic between remote employees and the corporate data center servers in this context","To detect, block, and remove malicious software from systems using signatures and behavior analysis","To manage the approval workflow for new user accounts and their assigned access permissions","To measure application performance and report slow response times to the operations team"], correct:1, explanation:"Anti-malware detects and removes malicious software; it does not encrypt VPN traffic or manage accounts." },
  { id:80243, domain:1, level:2, question:"What is the primary purpose of a change management process in security operations?", options:["To permit any administrator to modify production systems immediately without any review or record","To guarantee that no software or configuration will ever need to be updated after initial deployment","To ensure changes are reviewed, tested, and approved so they do not introduce new security risks","To transfer responsibility for every system change onto an external third-party service provider fully"], correct:2, explanation:"Change management reviews and approves changes to avoid new risk; uncontrolled changes are the opposite." },
  { id:80244, domain:1, level:3, question:"Why is scoping an incident correctly important during the analysis phase?", options:["Correct scoping guarantees the incident can be closed within one hour regardless of its complexity in this context","Scoping is only needed for compliance paperwork and has no effect on the technical response itself","Proper scoping allows the team to skip both the containment and the recovery phases entirely later","Accurate scoping reveals all affected systems so containment and eradication address the full impact"], correct:3, explanation:"Scoping identifies all affected systems so response is complete; missing scope leaves attackers a foothold." },
  { id:80245, domain:1, level:2, question:"Which of the following best describes the role of a threat actor?", options:["An individual or group that carries out or intends to carry out actions that harm information assets","A defensive control that automatically blocks malicious traffic before it reaches internal systems in this context","A regulatory body that issues fines to organizations that fail to protect personal customer data","A backup appliance that stores encrypted copies of production data for disaster recovery needs"], correct:0, explanation:"A threat actor is the person/group causing harm; a control, regulator, or backup is not a threat actor." },
  { id:80246, domain:1, level:2, question:"What is the difference between hacktivists and organized cybercriminals as threat actors?", options:["Hacktivists always operate legally, while organized cybercriminals only ever act with full authorization","Hacktivists are typically motivated by ideology or a cause, while cybercriminals seek financial gain","Hacktivists exclusively target hardware, while organized cybercriminals exclusively target software only","Hacktivists and organized cybercriminals share identical motivations and cannot be distinguished at all"], correct:1, explanation:"Hacktivists are ideologically driven while cybercriminals pursue profit; both act without authorization." },
  { id:80247, domain:1, level:3, question:"An organization discovers that logs on a compromised host were deleted by the attacker. This activity is best described as:", options:["Routine log rotation performed automatically by the operating system to conserve disk space","A recovery step in which the response team intentionally clears logs before restoring the system","Anti-forensics or log tampering intended to hinder investigation and hide the attacker's tracks","A precursor indicating that an attack is about to begin against the targeted host in the future"], correct:2, explanation:"Attacker-deleted logs are anti-forensics/log tampering, not routine rotation or a recovery step." },
  { id:80248, domain:1, level:1, question:"What is the purpose of a virtual private network (VPN) in security?", options:["To scan all endpoints for malware and quarantine any infected files that it discovers there","To store passwords for every employee in a central vault protected by a single master key","To automatically apply operating system patches to servers during scheduled maintenance","To create an encrypted tunnel that protects data as it travels across untrusted networks"], correct:3, explanation:"A VPN encrypts traffic over untrusted networks; malware scanning and patching are separate functions." },
  { id:80249, domain:1, level:2, question:"What is the main goal of the eradication step regarding attacker persistence mechanisms?", options:["To remove backdoors, rogue accounts, and other footholds so the attacker cannot easily return","To restore full business operations immediately before verifying that the systems are actually clean","To notify the public about the incident before the technical investigation has even been completed","To transfer the affected systems to an insurer so that the financial loss can be reimbursed quickly"], correct:0, explanation:"Eradication removes persistence like backdoors and rogue accounts; restoring service is recovery." },
  { id:80250, domain:1, level:3, question:"Why is it risky to restore a compromised system from a backup taken after the intrusion began?", options:["Backups taken after an intrusion are always corrupted and can never be successfully restored at all","The backup may already contain attacker artifacts, reintroducing the compromise upon restoration","Restoring any backup automatically deletes all logs needed for the ongoing incident investigation","A post-intrusion backup guarantees that the attacker can no longer access the restored system ever"], correct:1, explanation:"A post-intrusion backup may reintroduce malware/backdoors; clean, pre-compromise media is preferred." },
  { id:80251, domain:1, level:1, question:"What is the purpose of access control in information security?", options:["To increase the speed of the network by prioritizing traffic from the most important applications","To store encrypted backups of critical data in a geographically separate secondary location safely","To ensure that only authorized subjects can access specific resources based on defined permissions","To train employees on how to recognize and report suspicious phishing emails they might receive"], correct:2, explanation:"Access control restricts resource access to authorized subjects; it is not a backup or training function." },
  { id:80252, domain:1, level:2, question:"Which of the following best describes role-based access control (RBAC)?", options:["Every user is individually granted or denied access to each resource with no grouping of any kind in this context","Access is determined solely by the physical location of the device the user is connecting from","All users automatically receive administrator access unless a manager explicitly revokes it later","Access permissions are assigned to roles, and users receive permissions by being placed into roles"], correct:3, explanation:"RBAC ties permissions to roles that users are assigned; per-user grants without roles is a different model." },
  { id:80253, domain:1, level:2, question:"What is the primary purpose of a bring-your-own-device (BYOD) policy?", options:["To define security requirements and acceptable use for personal devices accessing company resources","To require every employee to purchase an identical company-issued laptop for all work-related tasks","To prohibit the use of any mobile device anywhere on the corporate network under all circumstances","To store the company's confidential data exclusively on employees' personal home computers only"], correct:0, explanation:"A BYOD policy sets security rules for personal devices; it neither mandates identical hardware nor bans mobiles." },
  { id:80254, domain:1, level:3, question:"An incident handler notes that an alert lacks context to confirm maliciousness and gathers more data. This reflects the importance of:", options:["Immediately containing every alert as if it were a confirmed high-severity incident without review","Enrichment and correlation during analysis to reduce false positives and confirm true incidents","Closing every ambiguous alert as benign so that the queue of open tickets stays small and clean","Escalating all alerts directly to executives before any technical analysis has been performed at all"], correct:1, explanation:"Enrichment and correlation confirm true incidents and cut false positives; blind closure or containment is unsound." },
  { id:80255, domain:1, level:1, question:"What is the purpose of a retention policy for logs and records?", options:["To ensure that all logs are deleted immediately after they are generated to save on storage costs in this context","To guarantee that no data is ever deleted so that storage capacity grows without any limit at all","To define how long data is kept so legal, operational, and investigative needs are met appropriately","To restrict log access exclusively to the marketing department for customer analytics purposes"], correct:2, explanation:"A retention policy balances how long records are kept for legal and investigative needs, not immediate deletion." },
  { id:80256, domain:1, level:2, question:"Which of the following is a benefit of automating parts of the incident response process?", options:["Complete elimination of the need for any human analysts or an incident response team going forward","A guarantee that every incident will be fully resolved without any escalation or human oversight","Automatic transfer of all legal liability for incidents to the vendor supplying the automation tool in this context","Faster, consistent handling of routine tasks so analysts can focus on complex decisions and analysis"], correct:3, explanation:"Automation speeds routine tasks and frees analysts; it does not eliminate the team or transfer liability." },
  { id:80257, domain:1, level:2, question:"What is the primary purpose of a security operations runbook for a specific alert type?", options:["To standardize the investigation and response steps so different analysts handle the alert consistently","To advertise the security team's capabilities to prospective clients and business partners externally in this context","To permanently store the encrypted backups of the systems most frequently affected by that alert","To calculate the annual budget required to license all of the security tools the team currently uses"], correct:0, explanation:"An alert runbook standardizes investigation/response for consistency; it is not a sales or backup tool." },
  { id:80258, domain:1, level:3, question:"Why is it important to distinguish an incident's containment strategy for short-term versus long-term needs?", options:["Short-term and long-term containment are identical, so distinguishing between them provides no value at all in this context","Short-term containment stops immediate spread while long-term measures allow safe, sustained operation during response","Long-term containment must always fully precede any short-term action to be effective during the incident","Containment strategy has no bearing on evidence preservation or on the eventual recovery of the systems"], correct:1, explanation:"Short-term containment halts spread quickly while long-term measures sustain operations; they serve distinct needs." },
  { id:80259, domain:1, level:1, question:"What is the purpose of an information security governance program?", options:["To handle only the physical maintenance of the building's heating and air conditioning systems in this context","To replace the technical security controls with a single annual policy document for auditors","To align security activities with business objectives through leadership, structure, and oversight","To manage the marketing budget allocated for promoting the organization's products each year"], correct:2, explanation:"Governance aligns security with business goals via leadership and oversight; it is not facilities or marketing." },
  { id:80260, domain:1, level:2, question:"Which of the following best describes the concept of residual risk?", options:["The total risk that exists before any security controls have been implemented at all yet","A risk that has been completely eliminated and can no longer affect the organization ever","The financial cost of purchasing and maintaining all of the organization's security controls","The risk that remains after security controls and treatments have been applied to reduce it"], correct:3, explanation:"Residual risk is what remains after controls are applied; risk before any control is inherent risk." },
  { id:80261, domain:1, level:2, question:"What is the main purpose of conducting a root cause analysis after an incident?", options:["To identify the underlying reason the incident occurred so similar incidents can be prevented later","To assign personal blame to an individual employee so that disciplinary action can be taken quickly","To immediately restore the affected systems before understanding how the compromise happened","To avoid documenting the incident so that it does not appear in any future compliance report"], correct:0, explanation:"Root cause analysis finds the underlying cause to prevent recurrence; it is not about assigning blame." },
  { id:80262, domain:1, level:3, question:"An organization wants to measure how quickly it detects incidents to improve its program. Which metric is most relevant?", options:["The total number of employees who completed annual security awareness training this calendar year","Mean time to detect, which measures the average interval between compromise and detection of it","The physical square footage occupied by the security operations center within the office building","The number of marketing leads generated by the company's public security blog over the quarter"], correct:1, explanation:"Mean time to detect measures detection speed; training counts and office size do not reflect detection." },
  { id:80263, domain:1, level:1, question:"What is the purpose of an incident report?", options:["To advertise the organization's strong security posture to potential customers and business partners","To calculate the depreciation schedule for all of the IT hardware assets across the organization","To document what happened, how it was handled, and the outcomes for accountability and learning","To replace the need for maintaining any audit logs on the systems involved in the incident later"], correct:2, explanation:"An incident report documents events, handling, and outcomes for accountability and learning; it is not marketing." },
  { id:80264, domain:1, level:2, question:"Which of the following is a common precursor that an attack may be forthcoming?", options:["A confirmed malware infection actively spreading across several endpoints within the network","Attacker deletion of critical audit logs on a server that has already been fully compromised","An intrusion detection system alerting on data being exfiltrated from an internal database","Newly published exploit code targeting a service that the organization is currently running"], correct:3, explanation:"Newly published exploit code for a running service is a precursor; active infection or exfiltration are indicators." },
  { id:80265, domain:1, level:2, question:"What is the primary purpose of a communication plan during a security incident?", options:["To ensure the right people receive accurate, timely information through predefined channels and contacts","To publish every technical detail of the incident publicly as soon as the first alert is triggered","To restrict all information about the incident so that not even the response team is informed of it in this context","To transfer responsibility for all incident decisions to the external public relations agency alone"], correct:0, explanation:"A communication plan delivers accurate, timely info through defined channels; it is not blanket secrecy or disclosure." },
  { id:80266, domain:1, level:3, question:"Why should evidence collection follow an order of volatility?", options:["The least volatile data, such as archived disks, must always be collected before anything else at all","The most volatile data, such as memory, is captured first because it is lost soonest if delayed","Order of volatility applies only to physical evidence and never to any form of digital evidence","Following an order of volatility removes the need to maintain any chain of custody documentation"], correct:1, explanation:"Order of volatility captures the most perishable data (memory) first; it does not waive chain of custody." },
  { id:80267, domain:1, level:1, question:"What is the purpose of an escalation matrix?", options:["To rank every employee by seniority so that promotions can be decided at the end of each year","To store the encrypted backups of every critical system in a prioritized recovery sequence order","To define who is notified and involved at each severity level so incidents reach the right people","To list the physical locations of all fire extinguishers throughout the organization's facilities"], correct:2, explanation:"An escalation matrix maps severity to who is notified/involved; it is not an HR ranking or a backup order." },
  { id:80268, domain:1, level:2, question:"Which of the following best distinguishes a virus from a worm?", options:["A virus self-propagates without any host, while a worm always requires a user to open an attachment","A virus affects only hardware components, while a worm affects only software applications running","A virus and a worm are identical in every respect and the two terms mean exactly the same thing","A virus needs a host file and user action to spread, while a worm self-propagates across networks"], correct:3, explanation:"A virus needs a host and user action; a worm self-propagates without a host, so they differ fundamentally." },
  { id:80269, domain:1, level:2, question:"What is the purpose of sandboxing suspicious files?", options:["To execute and observe them in an isolated environment so malicious behavior can be analyzed safely","To permanently store the files in an encrypted archive that no one is ever permitted to open again","To immediately distribute the files to every endpoint so that all users can inspect them themselves","To transfer the suspicious files to the vendor so that the vendor assumes all resulting liability"], correct:0, explanation:"Sandboxing runs files in isolation to observe behavior safely; it is not archival or distribution." },
  { id:80270, domain:1, level:3, question:"An organization notices repeated small data transfers to an external host to avoid triggering alerts. This technique is known as:", options:["A distributed denial-of-service flood intended to overwhelm the external host with massive traffic","Low-and-slow exfiltration designed to evade volume-based detection thresholds over an extended period","Routine cloud backup traffic that the response team can safely disregard without any investigation","A legitimate software update being pulled down from the vendor during a scheduled maintenance window in this context"], correct:1, explanation:"Small, gradual transfers to evade thresholds are low-and-slow exfiltration, not DoS or routine backup." },
  { id:80271, domain:1, level:1, question:"What does the term hardening refer to in security operations?", options:["Physically reinforcing server racks with steel plating to protect them from natural disasters","Increasing the clock speed of a processor so that security scans complete more quickly than before in this context","Reducing a system's attack surface by removing unnecessary services and applying secure configurations","Encrypting only the network traffic while leaving all stored data unprotected on the local disks"], correct:2, explanation:"Hardening reduces attack surface via secure configuration and removing unneeded services; it is not physical." },
  { id:80272, domain:1, level:2, question:"Which of the following is a primary responsibility of a forensic analyst on an IR team?", options:["Approving the annual information security budget and allocating funds to each department across the firm in this context","Writing and maintaining all of the organization's customer-facing marketing and advertising materials","Managing the physical building access badges and coordinating facility maintenance requests for staff","Collecting and examining digital evidence in a sound manner to support the investigation and any legal action"], correct:3, explanation:"A forensic analyst collects and examines digital evidence soundly; budgeting and facilities are other roles." },
  { id:80273, domain:1, level:2, question:"What is the purpose of a warning banner on systems and login screens?", options:["To notify users that activity may be monitored and to establish a legal basis for the monitoring performed","To display marketing advertisements to users so the organization can generate additional revenue easily in this context","To automatically encrypt all files stored on the system before the user is allowed to log in fully","To speed up the login process by pre-authenticating users based on their device's IP address alone"], correct:0, explanation:"A warning banner notifies of monitoring and supports its legal basis; it is not advertising or encryption." },
  { id:80274, domain:1, level:3, question:"Why is it important that incident responders coordinate with legal before disclosing a breach externally?", options:["Legal will handle every technical containment and eradication task instead of the incident response team","Legal ensures disclosures meet regulatory obligations and protect evidence and organizational interests appropriately","Coordinating with legal guarantees that the organization will not have to notify any affected individuals","Involving legal removes the requirement to document the incident or preserve any collected evidence at all in this context"], correct:1, explanation:"Legal ensures disclosures meet regulatory duties and protect interests; it does not perform technical containment." },
  { id:80275, domain:1, level:1, question:"What is the purpose of tokenization of sensitive data?", options:["To permanently delete all sensitive data so that it can never be recovered by anyone in the future","To increase the size of the database so that queries against sensitive records run faster than before","To replace sensitive values with non-sensitive substitutes so real data is not exposed during processing","To broadcast sensitive data across all systems so that every application can access it directly always in this context"], correct:2, explanation:"Tokenization substitutes non-sensitive tokens for real data to limit exposure; it does not delete or broadcast data." },
  { id:80276, domain:1, level:2, question:"Which of the following best describes the purpose of an incident handling checklist?", options:["To calculate the exact monetary value of every asset the organization owns for insurance purposes yearly","To advertise the incident response team's services to other departments and external partner organizations in this context","To permanently store the encrypted evidence collected from every past incident in a searchable archive","To provide a structured list of actions so responders do not overlook critical steps during a stressful incident"], correct:3, explanation:"A checklist ensures critical steps are not missed during response; it is not an asset valuation or archive." },
  { id:80277, domain:1, level:2, question:"What is a key characteristic of fileless malware?", options:["It operates primarily in memory and leverages legitimate tools, leaving little on-disk evidence to detect","It always writes a large executable file to disk that traditional antivirus can easily locate and remove in this context","It can only infect systems that have no antivirus software installed on them at the time of the attack","It is entirely harmless because it disappears from memory as soon as the affected system is rebooted"], correct:0, explanation:"Fileless malware runs in memory using legitimate tools, leaving little disk evidence; it is not harmless." },
  { id:80278, domain:1, level:3, question:"An organization uses deception technology to lure attackers to fake assets. The primary benefit is:", options:["A guarantee that attackers can never reach any of the organization's genuine production systems at all","Early detection of attacker activity and intelligence gathering while diverting them from real production assets","Complete elimination of the need for any other detection or monitoring controls across the environment","Automatic prosecution of any attacker who interacts with the decoy assets within the organization's network in this context"], correct:1, explanation:"Deception enables early detection and intel while diverting attackers; it does not guarantee immunity or prosecution." },
  { id:80279, domain:1, level:1, question:"What is the purpose of a security incident severity level?", options:["To rank employees by how many incidents they have personally reported over the current calendar year in this context","To determine the physical storage location where the evidence for that incident will be filed away","To indicate the potential impact and urgency of an incident so response effort can be scaled appropriately","To set the annual licensing cost of the security tools used to investigate that class of incident"], correct:2, explanation:"Severity indicates impact/urgency to scale response; it is not an HR ranking or a licensing figure." },
  { id:80280, domain:1, level:2, question:"Which of the following is an example of a detective control?", options:["A firewall rule that blocks all inbound connections from a specific range of untrusted IP addresses in this context","A door lock that physically prevents unauthorized individuals from entering the secured server room","An encryption algorithm that renders stored data unreadable to anyone without the decryption key","An intrusion detection system that alerts security staff when it observes suspicious network activity"], correct:3, explanation:"An IDS is a detective control that alerts after detecting activity; firewalls and locks are preventive controls." },
  { id:80281, domain:1, level:2, question:"What distinguishes a preventive control from a corrective control?", options:["A preventive control stops an incident before it happens, while a corrective control restores after one occurs","A preventive control only works after an incident, while a corrective control only works before one starts in this context","A preventive control applies to networks, while a corrective control applies only to physical facilities","A preventive control and a corrective control are identical and serve exactly the same purpose always"], correct:0, explanation:"Preventive controls stop incidents beforehand; corrective controls restore/repair after an incident occurs." },
  { id:80282, domain:1, level:3, question:"Why is it beneficial for an IR team to maintain relationships with external parties like ISPs and vendors before an incident?", options:["External parties will assume full responsibility for handling the organization's incidents from that point on","Established contacts enable faster assistance, information sharing, and coordinated response when time is critical","Maintaining these relationships removes the organization's obligation to build any internal response capability in this context","Prior relationships guarantee that the organization will never experience a serious security incident again"], correct:1, explanation:"Pre-established external contacts speed assistance and coordination; they do not remove internal capability needs." },
  { id:80283, domain:1, level:1, question:"What is the purpose of an incident response tabletop scenario library?", options:["To store the actual malware samples recovered from every past incident for redistribution to all staff in this context","To advertise the organization's security maturity to auditors so that no real testing is ever required","To provide realistic scenarios the team can rehearse so they are prepared for a range of incident types","To calculate the total number of alerts the security operations center processes in a typical month"], correct:2, explanation:"A scenario library supports rehearsal across incident types; it is not a malware store or an audit shortcut." },
  { id:80284, domain:1, level:2, question:"Which of the following best describes DNS tunneling as an attack technique?", options:["Flooding a DNS server with so many queries that it can no longer resolve legitimate name requests","Physically tampering with the DNS server hardware to redirect traffic to an attacker-owned facility","Sending phishing emails that spoof a well-known domain to trick recipients into revealing passwords","Encoding data or commands within DNS queries and responses to covertly bypass network controls"], correct:3, explanation:"DNS tunneling hides data in DNS traffic to bypass controls; flooding a DNS server is a denial-of-service attack." },
  { id:80285, domain:1, level:2, question:"What is the primary purpose of an out-of-band communication channel during an incident?", options:["To communicate securely even if the primary network or systems are compromised or unavailable during response","To increase the speed of routine business emails so that they are delivered faster than usual every day","To store the encrypted evidence collected during the incident in a location separate from the main network","To broadcast incident details publicly so that customers learn about the situation before internal staff do in this context"], correct:0, explanation:"Out-of-band channels keep responders communicating if primary systems are compromised; they are not for public broadcast." },
  { id:80286, domain:1, level:3, question:"An organization must decide whether an event qualifies as a reportable breach under applicable regulations. This decision most directly requires:", options:["Immediately rebuilding all affected systems from backups before any determination is made about the data in this context","Analyzing whether protected data was accessed or disclosed and applying the relevant legal notification criteria","Waiting until the next annual compliance audit to let the external auditors decide whether to report it","Escalating the technical containment tasks to the marketing team so they can manage public messaging"], correct:1, explanation:"Reportability hinges on whether protected data was accessed/disclosed against legal criteria, not on rebuilding first." },
  { id:80287, domain:1, level:1, question:"What is the main purpose of a vulnerability disclosure policy?", options:["To publicly announce every vulnerability the moment it is discovered before any patch is available at all","To prohibit anyone outside the organization from ever reporting security issues under any circumstances","To provide a clear, safe process for researchers to report discovered vulnerabilities to the organization","To transfer legal liability for all discovered vulnerabilities onto the researchers who report them in"], correct:2, explanation:"A disclosure policy gives researchers a safe reporting process; it does not force immediate public release." },
  { id:80288, domain:1, level:2, question:"Which of the following is a benefit of correlating events across multiple data sources?", options:["It eliminates the need to retain logs because correlated events are permanently stored in a summary only","It guarantees that every alert generated by any tool is automatically a confirmed true positive incident","It removes the requirement for analysts to investigate alerts since correlation resolves them by itself","It reveals patterns and attack activity that would be missed when viewing any single source in isolation"], correct:3, explanation:"Correlation across sources reveals patterns single sources miss; it does not auto-confirm every alert." },
  { id:80289, domain:1, level:2, question:"What is the purpose of a mobile device management (MDM) solution in incident prevention?", options:["To enforce security policies on mobile devices, such as encryption and remote wipe for lost or stolen units","To increase the battery life of employee smartphones so they can work longer without recharging them","To provide unlimited free data plans to all employees so they never need to use company Wi-Fi networks in this context","To store the organization's entire customer database directly on each employee's personal mobile phone"], correct:0, explanation:"MDM enforces policies like encryption and remote wipe on mobile devices; it is not a data plan or database store." },
  { id:80290, domain:1, level:3, question:"An analyst observes that malware communicates with a rotating set of domains generated algorithmically. This behavior indicates use of:", options:["A content delivery network used to speed up the loading of static assets on public web pages worldwide","A domain generation algorithm used to make command-and-control communication resilient to takedown efforts","A load balancer distributing legitimate application traffic evenly across several backend server instances","A routine software update mechanism that checks the vendor's single fixed domain for new versions daily"], correct:1, explanation:"Rotating algorithmically generated domains indicate a domain generation algorithm for resilient C2, not a CDN." },
  { id:80291, domain:1, level:1, question:"What is the purpose of an information security incident response capability?", options:["To guarantee that the organization will never again experience any form of security incident in the future","To replace all preventive controls such as firewalls and antivirus with a single reactive response process","To provide the people, processes, and tools needed to detect, respond to, and recover from incidents effectively","To handle only the physical security of the building while ignoring all logical and network security matters in this context"], correct:2, explanation:"An IR capability provides people, process, and tools to handle incidents; it does not replace preventive controls." },
  { id:80292, domain:1, level:2, question:"Which of the following best describes a compensating control?", options:["A control that is deliberately weaker than required so that legitimate business processes are not slowed down","A control that is applied only after an incident has occurred to permanently eliminate the root cause of it","A control that has been fully removed from the environment but is still listed in the policy documentation","An alternative safeguard implemented when a primary control is not feasible, providing comparable protection"], correct:3, explanation:"A compensating control substitutes for an infeasible primary control with comparable protection, not a weaker one." },
  { id:80293, domain:1, level:2, question:"What is the primary goal of the recovery phase regarding validation?", options:["To confirm that restored systems are clean and functioning normally before returning them to production use","To immediately return systems to production without any testing so that downtime is minimized as much as possible","To permanently isolate the affected systems so that they can never be reconnected to the network again","To assign disciplinary blame to the staff members who were on duty when the incident first occurred"], correct:0, explanation:"Recovery validation confirms systems are clean and functional before production; skipping testing risks reinfection." },
  { id:80294, domain:1, level:3, question:"Why is understanding the difference between an event, an alert, and an incident important for responders?", options:["It allows responders to treat every single observed event as a confirmed high-severity incident automatically","It ensures responders correctly triage observations so that genuine incidents receive appropriate attention and effort","It removes the need for any detection tools because the definitions alone will surface all real incidents reliably in this context","It guarantees that no false positives will ever be generated by any of the monitoring systems in place"], correct:1, explanation:"Distinguishing events, alerts, and incidents supports correct triage so real incidents get attention; it does not remove tooling." },
  { id:80295, domain:1, level:1, question:"What is the purpose of least functionality on a system?", options:["To grant every installed application full administrative privileges so that support tickets decrease sharply","To enable all available services and ports by default so that future needs are always accommodated instantly","To configure systems to provide only essential capabilities, reducing the number of exploitable features","To store all system backups on the same host so that recovery does not depend on any external media at all"], correct:2, explanation:"Least functionality limits systems to essential capabilities to shrink attack surface; enabling everything is the opposite." },
  { id:80296, domain:1, level:2, question:"Which of the following is a primary purpose of gathering threat intelligence for incident response?", options:["To generate promotional content that highlights the organization's security investments to prospective clients","To permanently eliminate the need for detection tools because intelligence alone prevents all intrusions reliably","To calculate the resale value of used security hardware being retired from the organization's data center","To understand adversary tactics and indicators so the team can detect, prioritize, and respond more effectively"], correct:3, explanation:"Threat intelligence informs detection, prioritization, and response; it does not replace tools or serve marketing." },
  { id:80297, domain:1, level:2, question:"What is the primary purpose of a post-incident review meeting?", options:["To evaluate the response, identify improvements, and update plans and controls to strengthen future readiness","To publicly assign blame to a specific individual so that disciplinary action can be pursued immediately","To close the incident record instantly without discussing what went well or what could be improved later","To advertise the successful resolution of the incident to the organization's customers and partners externally"], correct:0, explanation:"A post-incident review evaluates the response and drives improvement; it is not for blame or advertising." },
  { id:80298, domain:1, level:3, question:"An organization wants incident metrics that demonstrate improvement over time to leadership. Which pairing is most useful?", options:["The number of coffee cups consumed by the SOC and the square footage of the operations center floor","Mean time to detect and mean time to respond, tracked over time to show measurable operational improvement","The count of marketing emails sent and the number of social media followers gained during each quarter in this context","The total number of physical door badges issued and the number of parking permits assigned to staff"], correct:1, explanation:"Mean time to detect and respond are meaningful IR improvement metrics; the other pairings are unrelated to IR." },
  { id:80299, domain:1, level:2, question:"Which of the following best explains why insider threats can be harder to detect than external attacks?", options:["Insiders always operate from outside the corporate network, making their traffic obvious to perimeter defenses","Insiders never have any access to sensitive data, so any access they attempt immediately triggers an alert","Insiders often have legitimate access and knowledge, so their malicious actions can resemble normal activity","Insiders can only act during scheduled maintenance windows, which are already heavily monitored by the team"], correct:2, explanation:"Insiders' legitimate access lets malicious actions blend with normal activity; they are not confined to outside the network." },
  { id:80300, domain:1, level:3, question:"An organization aligns its incident handling with NIST SP 800-61 and ISO/IEC 27035. The main benefit of using recognized frameworks is:", options:["Guaranteeing that the organization will never experience a successful security incident once the frameworks are adopted","Removing the need to tailor any procedures to the organization's specific environment, risks, and business context","Transferring all legal liability for future breaches to the standards bodies that authored those frameworks originally","Providing a structured, repeatable, and defensible process that improves consistency and supports compliance efforts"], correct:3, explanation:"Recognized frameworks give a structured, repeatable, defensible process supporting compliance; they do not guarantee immunity." }
];
if (typeof window !== 'undefined') window.QUESTIONS_ECIH_C1 = QUESTIONS_ECIH_C1;
